import{_ as a,o as t,c as s,a0 as n}from"./chunks/framework.jwovEGr5.js";const u=JSON.parse('{"title":"Work Inside an Instance","description":"","frontmatter":{},"headers":[],"relativePath":"how-to/instance-detail.md","filePath":"how-to/instance-detail.md"}'),i={name:"how-to/instance-detail.md"};function o(r,e,l,c,h,d){return t(),s("div",null,[...e[0]||(e[0]=[n('<h1 id="work-inside-an-instance" tabindex="-1">Work Inside an Instance <a class="header-anchor" href="#work-inside-an-instance" aria-label="Permalink to &quot;Work Inside an Instance&quot;">​</a></h1><p>An instance detail page is the working area for one event run. This is where you review the session setup, participant snapshot, source batches, and saved result rows.</p><blockquote><p>Screenshot placeholder: instance-detail.png</p></blockquote><h2 id="what-you-can-see-at-the-top" tabindex="-1">What you can see at the top <a class="header-anchor" href="#what-you-can-see-at-the-top" aria-label="Permalink to &quot;What you can see at the top&quot;">​</a></h2><p>The summary table shows:</p><ul><li>kingdom and alliance</li><li>date range</li><li>current stage and total stages</li><li>duration mode and score-entry mode</li><li>scoring behavior</li><li>lock state</li><li>number of source batches</li></ul><h2 id="participant-snapshot" tabindex="-1">Participant snapshot <a class="header-anchor" href="#participant-snapshot" aria-label="Permalink to &quot;Participant snapshot&quot;">​</a></h2><p>For normal events, the instance page shows the event snapshot or eligible-player list. This is where you can see:</p><ul><li>the event alliance</li><li>the player&#39;s current alliance</li><li>the eligibility status</li><li>join and leave snapshot dates</li><li>review warnings</li></ul><p>If a status is unclear, use <a href="./../reference/participant-eligibility.html">Participant Eligibility Statuses</a>.</p><h2 id="stage-dates" tabindex="-1">Stage dates <a class="header-anchor" href="#stage-dates" aria-label="Permalink to &quot;Stage dates&quot;">​</a></h2><p>For multi-stage events, the page can show a <strong>Stage Dates</strong> section. Senior editors can update those dates unless the instance is locked.</p><h2 id="session-rows-and-source-batches" tabindex="-1">Session rows and source batches <a class="header-anchor" href="#session-rows-and-source-batches" aria-label="Permalink to &quot;Session rows and source batches&quot;">​</a></h2><p>Lower on the page, you can review:</p><ul><li><strong>Source Batches</strong> that fed the instance</li><li><strong>Session Rows</strong> for the saved results themselves</li></ul><p>That makes the page useful both for &quot;where did this come from?&quot; and for direct row cleanup.</p><h2 id="special-case-kingdom-of-power" tabindex="-1">Special case: Kingdom of Power <a class="header-anchor" href="#special-case-kingdom-of-power" aria-label="Permalink to &quot;Special case: Kingdom of Power&quot;">​</a></h2><p>KvK instances show extra snapshot information and a link into the separate KvK Prep workflow. Use <a href="./kvk-prep.html">Run a KvK Prep Session</a> for before/after power capture.</p><h2 id="locked-instances" tabindex="-1">Locked instances <a class="header-anchor" href="#locked-instances" aria-label="Permalink to &quot;Locked instances&quot;">​</a></h2><p>If the event is locked, editing and importing are blocked until the instance is unlocked. See <a href="./session-lock.html">Locked Instances &amp; Unlock Requests</a>.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./create-instance.html">Create an Event Instance</a></li><li><a href="./session-lock.html">Locked Instances &amp; Unlock Requests</a></li><li><a href="./records.html">Records &amp; Record Batches</a></li></ul>',22)])])}const m=a(i,[["render",o]]);export{u as __pageData,m as default};
